-- Optional starter content for CIVICAVITA's public blog.
-- These are editorial introductions, not reports of funded projects or partnerships.
INSERT OR IGNORE INTO posts (id,title,excerpt,content,category,author,author_role,date,cover_emoji,read_minutes,tags) VALUES
('civicavita-editorial-evidence',
 'Evidence before claims: how CIVICAVITA publishes public work',
 'A short editorial note on transparent scope, careful attribution and the difference between individual experience and institutional claims.',
 'CIVICAVITA AB works where global health, humanitarian science and responsible AI meet. That work needs clarity as much as ambition.\n\nWe will distinguish the professional history of our founder from work undertaken by CIVICAVITA AB. We will not describe an institution as a partner, a project as active, or an outcome as achieved unless we can support that statement.\n\nThis is not a limitation. It is a publishing standard. It helps collaborators, readers and communities understand what is established, what is being explored, and what still requires evidence.',
 'Editorial','CIVICAVITA AB','Editorial team','2026-07-21','🔎',2,'["Evidence","Transparency","Global Health"]'),
('civicavita-editorial-ai',
 'Responsible AI starts with accountable human judgment',
 'AI can support research and communication, but it cannot replace contextual knowledge, ethical review or responsibility for decisions.',
 'In global health and humanitarian settings, a fluent output is not the same as a reliable one. Data may be incomplete, contexts change quickly and the consequences of error can be serious.\n\nCIVICAVITA uses AI as an assistive tool for structured drafting, knowledge management and research workflows. Human review remains essential. Sources must be checked, uncertainty must be stated and affected communities must not be reduced to data points.\n\nThe question is not whether to use AI. The question is how to use it with appropriate safeguards, transparency and accountability.',
 'Responsible AI','CIVICAVITA AB','Editorial team','2026-07-21','🧠',2,'["Responsible AI","Ethics","Research"]'),
('civicavita-editorial-systems',
 'Health systems resilience is a long-term practice',
 'Resilience is not a slogan or a single technology. It is the capacity to learn, adapt and continue providing essential care under pressure.',
 'Health systems face overlapping pressures: climate risk, displacement, chronic disease, workforce constraints and uneven access to information. Useful responses require more than short-term solutions.\n\nThey require attention to local capacity, public institutions, routine data, continuity of care and the realities experienced by patients and frontline workers. Research and advisory work should make these realities more visible, not obscure them.\n\nCIVICAVITA will publish practical notes on these questions as its research and advisory work develops.',
 'Health Systems','CIVICAVITA AB','Editorial team','2026-07-21','🏥',2,'["Health Systems","Resilience","Policy"]');
